import{_ as t,o as i,c as r,a2 as a}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"ADR-046 — Agency-first build-time imagery sourcing","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-046.md","filePath":"adr/ADR-046.md"}'),o={name:"adr/ADR-046.md"};function n(s,e,l,c,d,g){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-046-—-agency-first-build-time-imagery-sourcing" tabindex="-1">ADR-046 — Agency-first build-time imagery sourcing <a class="header-anchor" href="#adr-046-—-agency-first-build-time-imagery-sourcing" aria-label="Permalink to &quot;ADR-046 — Agency-first build-time imagery sourcing&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-06 Extends · <code>docs/adr/ADR-016.md</code> (build-time bundle unchanged) Scope · <code>scripts/fetch-assets.ts</code>, mission/panel/ISS imagery under <code>static/images/</code></p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-016 requires all imagery to be fetched at <strong>build time</strong> and served from the app host. Today <code>scripts/fetch-assets.ts</code> leans heavily on the <strong>NASA Images API</strong> plus curated Wikimedia Commons filenames. That often yields correct NASA missions but <strong>wrong context</strong> for non-NASA operators (e.g. Soyuz, Tiangong, SpaceX hardware) or generic diagrams when agency-specific sources were never queried first.</p><p>Product expectation: <strong>prefer imagery from the agency that operated the mission or object</strong>, then fall back to partner archives and general libraries.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ol><li><p><strong>Build-time only</strong> — No change to ADR-016: production still ships zero runtime third-party image URLs.</p></li><li><p><strong>Primary source = operating agency</strong> (conceptual rule; encoded per entity in fetch helpers):</p><ul><li><strong>Roscosmos / Soviet heritage</strong> — Russian programmes (e.g. Soyuz, GLONASS-class editorial, lunar/rovers where Roscosmos holds primary press assets).</li><li><strong>CNSA</strong> — Chinese programmes (e.g. Tiangong, Chang’e, Tianwen where Chinese agencies publish primary material).</li><li><strong>SpaceX</strong> — SpaceX vehicles and programmes where SpaceX (or explicitly licensed partner releases) are the authoritative visual source.</li><li><strong>NASA</strong> — NASA-led missions and <strong>default baseline</strong> when ownership is US NASA primary or no tighter agency mapping exists.</li></ul></li><li><p><strong>Fallback order</strong> (when primary yields nothing usable — HTTP failure, empty catalog, policy block):</p><ul><li>Co-operating / partner agency archives (e.g. ESA for joint programmes where applicable).</li><li><strong>Wikimedia Commons</strong> — curated filenames verified PD / CC-* compatible with our credits pipeline.</li><li><strong>NASA Images API</strong> — retained as a <strong>broad aerospace library</strong>, not the automatic first hop for every entity.</li></ul></li><li><p><strong>Mixed programmes</strong> (e.g. ISS): use an explicit <strong>published rule table</strong> in implementation — e.g. primary poster / lead partner for that catalog row — so behaviour is deterministic in CI.</p></li><li><p><strong>License &amp; attribution</strong> — Each adapter records provenance so gallery credits remain accurate (NASA PD-style vs ESA CC BY-SA IGO vs Commons attribution). Implementation must not merge incompatible license strings blindly into one generic “NASA” credit.</p></li></ol><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li>Aligns hero/gallery imagery with <strong>who flew the hardware</strong>, improving trust and editorial clarity.</li><li>Keeps offline-first and ADR-016 contracts intact.</li><li>Makes NASA a <strong>strong fallback</strong>, not a silent substitute for agency-owned stories.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>NASA-only forever</strong> — simplest implementation; rejected for context mismatches above.</li><li><strong>Wikimedia-only</strong> — good for PD/CC breadth; weak as sole primary for agency-branded campaigns.</li><li><strong>Runtime agency APIs</strong> — violates ADR-016; rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive:</p><ul><li>Clearer editorial policy for future fetch helpers and curated lists.</li></ul><p>Negative:</p><ul><li>More adapters and maintenance (rate limits, URL churn per agency).</li><li>Legal/editorial review for non-NASA terms until helpers are stable.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Implement in <strong><code>scripts/fetch-assets.ts</code></strong> (and shared helpers colocated there unless split later): unified “candidate URLs” pipeline with <strong>agency priority + fallback</strong>, same <code>01.jpg…</code> manifest layout as today.</li><li><strong><code>docs/adr/index.md</code></strong> lists this ADR; mission imagery bullet in ADR-016 references this decision for <strong>source priority</strong> (not transport).</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>ADR-016 — build-time assets (transport).</li><li>Implementation tracking: GitHub <strong>#44</strong> — <em>Implement ADR-046: agency-first build-time imagery sourcing</em>.</li></ul>',20)])])}const u=t(o,[["render",n]]);export{p as __pageData,u as default};
